import React, { useState, useEffect } from 'react';
import Layout from './Layout';
import API from '../api/api';
import { FaHeart, FaComment, FaShare, FaMapMarkerAlt, FaGlobeAsia, FaTrophy, FaMedal, FaCrown, FaFire, FaPlane, FaCamera } from 'react-icons/fa';
import './Community.css';

// Simulated community data (in production, this would come from API)
const mockTravelers = [
  { name: 'Aarav Sharma', avatar: 'AS', states: 18, countries: 12, destinations: 87, bio: 'Mountain lover. 18 states and counting.', badge: 'Adventurer' },
  { name: 'Meera Patel', avatar: 'MP', states: 24, countries: 8, destinations: 142, bio: 'Temple trail enthusiast. South India expert.', badge: 'Wanderer' },
  { name: 'Rohan Das', avatar: 'RD', states: 12, countries: 22, destinations: 65, bio: 'Global backpacker. India is home base.', badge: 'Explorer' },
  { name: 'Ananya Iyer', avatar: 'AI', states: 28, countries: 5, destinations: 210, bio: 'Completed all 28 states! Now exploring UTs.', badge: 'All India' },
  { name: 'Vikram Singh', avatar: 'VS', states: 15, countries: 18, destinations: 95, bio: 'Weekend warrior. Road trips are life.', badge: 'Explorer' },
  { name: 'Kavya Nair', avatar: 'KN', states: 9, countries: 3, destinations: 45, bio: 'Just started my journey. Kerala born.', badge: 'First Step' },
];

const mockFeed = [
  { user: 'Aarav Sharma', avatar: 'AS', action: 'visited', place: 'Ladakh', type: 'state', time: '2 hours ago', likes: 24, comments: 5, text: 'Finally made it to Pangong Lake! The blue water against the mountains is unreal.' },
  { user: 'Meera Patel', avatar: 'MP', action: 'completed', place: 'Tamil Nadu', type: 'milestone', time: '5 hours ago', likes: 42, comments: 12, text: 'All top destinations in Tamil Nadu done! Mahabalipuram was the highlight.' },
  { user: 'Rohan Das', avatar: 'RD', action: 'visited', place: 'Japan', type: 'country', time: '1 day ago', likes: 56, comments: 8, text: 'Cherry blossom season in Kyoto. 22nd country on my map!' },
  { user: 'Ananya Iyer', avatar: 'AI', action: 'unlocked', place: 'All India Badge', type: 'badge', time: '2 days ago', likes: 128, comments: 34, text: 'ALL 28 STATES DONE! This journey took 4 years. Every state has a story.' },
  { user: 'Vikram Singh', avatar: 'VS', action: 'planned', place: 'Northeast Road Trip', type: 'plan', time: '3 days ago', likes: 18, comments: 7, text: 'Planning a 15-day road trip through the Seven Sisters. Who has recommendations?' },
];

const badgeColors = {
  'First Step': '#94a3b8',
  'Explorer': '#3b82f6',
  'Adventurer': '#8b5cf6',
  'Wanderer': '#f59e0b',
  'Nomad': '#ec4899',
  'All India': '#10b981',
};

function getActionIcon(type) {
  switch (type) {
    case 'state': return <FaMapMarkerAlt />;
    case 'country': return <FaGlobeAsia />;
    case 'milestone': return <FaTrophy />;
    case 'badge': return <FaMedal />;
    case 'plan': return <FaPlane />;
    default: return <FaCamera />;
  }
}

function getActionColor(type) {
  switch (type) {
    case 'state': return '#10b981';
    case 'country': return '#3b82f6';
    case 'milestone': return '#f59e0b';
    case 'badge': return '#8b5cf6';
    case 'plan': return '#ec4899';
    default: return '#64748b';
  }
}

export default function Community() {
  const [activeTab, setActiveTab] = useState('feed');
  const [user, setUser] = useState({ name: 'Explorer' });
  const [myStats, setMyStats] = useState({ states: 0, countries: 0, destinations: 0 });
  const [likedPosts, setLikedPosts] = useState({});

  useEffect(() => {
    try {
      const stored = JSON.parse(localStorage.getItem('user'));
      if (stored?.name) setUser(stored);
    } catch {}
    // Fetch real user stats
    async function fetchStats() {
      try {
        const [selRes, visitRes] = await Promise.all([
          API.get('/api/user/selected'),
          API.get('/api/user/visited-destinations'),
        ]);
        const locs = selRes.data.selectedLocations || [];
        setMyStats({
          states: locs.filter(l => !l.type || l.type !== 'country').length,
          countries: locs.filter(l => l.type === 'country').length,
          destinations: (visitRes.data.visitedDestinations || []).length,
        });
      } catch {}
    }
    fetchStats();
  }, []);

  const toggleLike = (i) => {
    setLikedPosts(prev => ({ ...prev, [i]: !prev[i] }));
  };

  const getInitials = (name) => name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);
  const myRank = mockTravelers.filter(t => t.states > myStats.states).length + 1;

  return (
    <Layout>
      <div className="community-page">
        {/* Header */}
        <div className="community-header">
          <div>
            <h1 className="page-title">Community</h1>
            <p className="page-subtitle">See what fellow travelers are exploring</p>
          </div>
          <div className="community-tabs">
            <button className={`ctab ${activeTab === 'feed' ? 'active' : ''}`} onClick={() => setActiveTab('feed')}>
              <FaFire /> Feed
            </button>
            <button className={`ctab ${activeTab === 'leaderboard' ? 'active' : ''}`} onClick={() => setActiveTab('leaderboard')}>
              <FaTrophy /> Leaderboard
            </button>
            <button className={`ctab ${activeTab === 'discover' ? 'active' : ''}`} onClick={() => setActiveTab('discover')}>
              <FaGlobeAsia /> Discover
            </button>
          </div>
        </div>

        <div className="community-layout">
          {/* Main content */}
          <div className="community-main">
            {activeTab === 'feed' && (
              <div className="feed-list">
                {mockFeed.map((post, i) => (
                  <div key={i} className="feed-card" style={{ '--i': i }}>
                    <div className="feed-top">
                      <div className="feed-user">
                        <div className="feed-avatar" style={{ background: `linear-gradient(135deg, ${getActionColor(post.type)}, ${getActionColor(post.type)}dd)` }}>
                          {post.avatar}
                        </div>
                        <div>
                          <span className="feed-username">{post.user}</span>
                          <span className="feed-action">
                            <span className="feed-action-icon" style={{ color: getActionColor(post.type) }}>{getActionIcon(post.type)}</span>
                            {post.action} <strong>{post.place}</strong>
                          </span>
                        </div>
                      </div>
                      <span className="feed-time">{post.time}</span>
                    </div>
                    <p className="feed-text">{post.text}</p>
                    <div className="feed-actions">
                      <button className={`feed-btn ${likedPosts[i] ? 'liked' : ''}`} onClick={() => toggleLike(i)}>
                        <FaHeart /> {post.likes + (likedPosts[i] ? 1 : 0)}
                      </button>
                      <button className="feed-btn"><FaComment /> {post.comments}</button>
                      <button className="feed-btn"><FaShare /> Share</button>
                    </div>
                  </div>
                ))}
              </div>
            )}

            {activeTab === 'leaderboard' && (
              <div className="leaderboard">
                <div className="lb-podium">
                  {mockTravelers.sort((a, b) => b.states - a.states).slice(0, 3).map((t, i) => (
                    <div key={i} className={`lb-podium-item pos-${i + 1}`}>
                      <div className="lb-crown">{i === 0 ? <FaCrown /> : <FaMedal />}</div>
                      <div className="lb-podium-avatar" style={{ background: i === 0 ? 'linear-gradient(135deg, #fbbf24, #f59e0b)' : i === 1 ? 'linear-gradient(135deg, #94a3b8, #64748b)' : 'linear-gradient(135deg, #d97706, #b45309)' }}>
                        {t.avatar}
                      </div>
                      <span className="lb-podium-name">{t.name.split(' ')[0]}</span>
                      <span className="lb-podium-score">{t.states} states</span>
                    </div>
                  ))}
                </div>
                <div className="lb-table">
                  {mockTravelers.sort((a, b) => b.states - a.states).map((t, i) => (
                    <div key={i} className={`lb-row ${i < 3 ? 'top-3' : ''}`}>
                      <span className="lb-rank">#{i + 1}</span>
                      <div className="lb-row-avatar">{t.avatar}</div>
                      <div className="lb-row-info">
                        <span className="lb-row-name">{t.name}</span>
                        <span className="lb-row-badge" style={{ background: `${badgeColors[t.badge]}20`, color: badgeColors[t.badge] }}>{t.badge}</span>
                      </div>
                      <div className="lb-row-stats">
                        <span>{t.states} states</span>
                        <span>{t.countries} countries</span>
                        <span>{t.destinations} dest.</span>
                      </div>
                    </div>
                  ))}
                  {/* Your position */}
                  <div className="lb-row lb-you">
                    <span className="lb-rank">#{myRank}</span>
                    <div className="lb-row-avatar">{getInitials(user.name)}</div>
                    <div className="lb-row-info">
                      <span className="lb-row-name">{user.name} <span className="lb-you-tag">You</span></span>
                    </div>
                    <div className="lb-row-stats">
                      <span>{myStats.states} states</span>
                      <span>{myStats.countries} countries</span>
                      <span>{myStats.destinations} dest.</span>
                    </div>
                  </div>
                </div>
              </div>
            )}

            {activeTab === 'discover' && (
              <div className="discover-grid">
                {mockTravelers.map((t, i) => (
                  <div key={i} className="discover-card" style={{ '--i': i }}>
                    <div className="dc-avatar" style={{ background: `linear-gradient(135deg, ${Object.values(badgeColors)[i % 6]}, ${Object.values(badgeColors)[(i + 2) % 6]})` }}>
                      {t.avatar}
                    </div>
                    <h3 className="dc-name">{t.name}</h3>
                    <p className="dc-bio">{t.bio}</p>
                    <div className="dc-badge" style={{ background: `${badgeColors[t.badge]}15`, color: badgeColors[t.badge] }}>
                      <FaMedal /> {t.badge}
                    </div>
                    <div className="dc-stats">
                      <div className="dc-stat"><strong>{t.states}</strong><span>States</span></div>
                      <div className="dc-stat"><strong>{t.countries}</strong><span>Countries</span></div>
                      <div className="dc-stat"><strong>{t.destinations}</strong><span>Places</span></div>
                    </div>
                    <button className="dc-follow">Follow</button>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Right sidebar */}
          <aside className="community-sidebar">
            {/* Your travel card */}
            <div className="my-travel-card">
              <div className="mtc-header">
                <div className="mtc-avatar">{getInitials(user.name)}</div>
                <div>
                  <div className="mtc-name">{user.name}</div>
                  <div className="mtc-rank">Rank #{myRank} Explorer</div>
                </div>
              </div>
              <div className="mtc-stats">
                <div className="mtc-stat"><strong>{myStats.states}</strong><span>States</span></div>
                <div className="mtc-stat"><strong>{myStats.countries}</strong><span>Countries</span></div>
                <div className="mtc-stat"><strong>{myStats.destinations}</strong><span>Dest.</span></div>
              </div>
            </div>

            {/* Trending destinations */}
            <div className="trending-card">
              <h3><FaFire style={{ color: '#f59e0b' }} /> Trending</h3>
              <div className="trending-list">
                {['Ladakh', 'Goa', 'Manali', 'Kerala Backwaters', 'Hampi'].map((place, i) => (
                  <div key={i} className="trending-item">
                    <span className="trending-rank">#{i + 1}</span>
                    <span className="trending-name">{place}</span>
                    <span className="trending-fire"><FaFire /></span>
                  </div>
                ))}
              </div>
            </div>
          </aside>
        </div>
      </div>
    </Layout>
  );
}
